const patchB64="";
function sha(file){return crypto.createHash("sha256").update(fs.readFileSync(file)).digest("hex");}
function stateFor(expected){
  return Object.keys(expected).every(function(rel){
    const full=path.join(repo,rel),want=expected[rel];
    if(want===null)return !fs.existsSync(full);
    return fs.existsSync(full)&&sha(full)===want;
  });
}
